const taxRows = $('Pull Tax Delinquent Records').first().json.tax_delinquent || [];
const vacantRows = $('Pull Vacant Properties').first().json.vacant_properties || [];
const absenteeRows = $('Pull Absentee Owners').first().json || [];

const leadsToCreate = [];

for (const t of taxRows.slice(0, 20)) {
  leadsToCreate.push({ lead_type: 'Seller', source: 'Public Records', status: 'New', notes: `Tax delinquent ${t.years_delinquent} yrs — $${t.amount_owed} owed`, metadata: { address: t.address, tax_delinquent: true, amount_owed: t.amount_owed } });
}

for (const v of vacantRows.slice(0, 20)) {
  leadsToCreate.push({ lead_type: 'Seller', source: 'Drive-By', status: 'New', notes: `Vacant ${v.vacancy_type} — ${v.years_vacant} yrs`, metadata: { address: v.address, vacant: true, vacancy_type: v.vacancy_type } });
}

for (const a of absenteeRows.slice(0, 10)) {
  leadsToCreate.push({ lead_type: 'Seller', source: 'Public Records', status: 'New', notes: `Absentee owner — ${a.owner_type}`, metadata: { address: a.address, absentee_owner: true } });
}

return leadsToCreate.map(l => ({ json: l }));

